/**
 * This example demonstrates how to use the SDK behind an HTTP proxy
 */

import {Config, WorkspaceClient} from "../src";
import {ProxyAgent} from "proxy-agent";

/**
 * Example to show logged in user information
 */
async function main() {
    const config = new Config({});
    await config.ensureResolved();

    const agent = new ProxyAgent({
        rejectUnauthorized: !config.skipVerify,
    });

    const client = new WorkspaceClient(config, {agent});

    console.log(await client.currentUser.me());
}

main();
